 30→            text-align: center;
 31→            margin-bottom: 30px;
 32→            padding: 20px;
 33→            background: white;
 34→            border-radius: 10px;
 35→            box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
 36→        }
 37→        
 38→        h1 {
 39→            color: #2c3e50;
 40→            margin-bottom: 10px;
 41→            font-size: 2.2em;
 42→        }
 43→        
 44→        .subtitle {
 45→            color: #7f8c8d;
 46→            font-size: 1.1em;
 47→            margin-bottom: 20px;
 48→        }
 49→        
 50→        .filters {
 51→            display: flex;
 52→            justify-content: center;
