 80→            max-width: 600px;
 81→        }
 82→        
 83→        #searchInput {
 84→            width: 100%;
 85→            padding: 12px 20px;
 86→            border: 2px solid #ddd;
 87→            border-radius: 25px;
 88→            font-size: 1em;
 89→            transition: border-color 0.3s;
 90→        }
 91→        
 92→        #searchInput:focus {
 93→            outline: none;
 94→            border-color: #3498db;
 95→        }
 96→        
 97→        .table-container {
 98→            background: white;
 99→            border-radius: 10px;
100→            overflow: hidden;
101→            box-shadow: 0 4px 20px rgba(0, 0, 0, 0.1);
102→            margin-bottom: 30px;
103→            overflow-x: auto;
104→        }
105→        
106→        table {
107→            width: 100%;
108→            border-collapse: collapse;
109→            min-width: 1200px;
110→        }
111→        
112→        thead {
113→            background: linear-gradient(135deg, #2c3e50 0%, #4a6491 100%);
114→            color: white;
115→        }
116→        
117→        th {
118→            padding: 18px 15px;
119→            text-align: left;
120→            font-weight: 600;
121→            font-size: 0.95em;
122→            border-right: 1px solid rgba(255, 255, 255, 0.1);
123→        }
124→        
125→        th:last-child {
126→            border-right: none;
127→        }
128→        
