137→            transition: background-color 0.2s;
138→        }
139→        
140→        tbody tr:hover {
141→            background-color: #f8f9fa;
142→        }
143→        
144→        td {
145→            padding: 16px 15px;
146→            vertical-align: top;
147→            border-right: 1px solid #eee;
148→        }
149→        
150→        td:last-child {
151→            border-right: none;
152→        }
153→        
154→        .category-row {
155→            background-color: #2980b9 !important;
156→            color: white;
157→            font-weight: bold;
158→            font-size: 1.1em;
159→        }
160→        
161→        .sub-category {
162→            background-color: #e3f2fd !important;
163→            font-weight: bold;
164→            color: #1565c0;
165→        }
166→        
167→        .time-limit {
168→            color: #27ae60;
169→            font-weight: bold;
170→            font-size: 1.05em;
171→        }
172→        
173→        .warning {
