217→            100% { background-color: transparent; }
218→        }
219→        
220→        footer {
221→            text-align: center;
222→            margin-top: 40px;
223→            padding: 20px;
224→            color: #7f8c8d;
225→            font-size: 0.9em;
226→            border-top: 1px solid #eee;
227→        }
228→        
229→        @media (max-width: 768px) {
230→            .container {
231→                padding: 10px;
232→            }
233→            
234→            h1 {
235→                font-size: 1.8em;
236→            }
237→            
238→            .filter-btn {
239→                padding: 6px 15px;
240→                font-size: 0.85em;
241→            }
242→            
243→            th, td {
244→                padding: 12px 10px;
245→                font-size: 0.9em;
246→            }
247→        }
248→        
249→        .copy-btn {
250→            background: #2ecc71;
251→            color: white;
252→            border: none;
253→            padding: 8px 15px;
254→            border-radius: 4px;
255→            cursor: pointer;
256→            margin-left: 10px;
257→            transition: background 0.3s;
258→        }
259→        
260→        .copy-btn:hover {
261→            background: #27ae60;
262→        }
263→    </style>
264→</head>
265→<body>
266→    <div class="container">
267→        <header>
268→            <h1>📋 全面法律期限规定汇总表</h1>
269→            <p class="subtitle">基于《民法典》、《民事诉讼法》、《劳动合同法》等法律法规整理</p>
270→            
271→            <div class="search-box">
272→                <input type="text" id="searchInput" placeholder="搜索法律期限、权利名称或关键词...">
273→            </div>
274→            
275→            <div class="filters">
276→                <button class="filter-btn active" data-filter="all">全部期限</button>
277→                <button class="filter-btn" data-filter="civil">民事实体</button>
278→                <button class="filter-btn" data-filter="procedure">诉讼程序</button>
279→                <button class="filter-btn" data-filter="labor">劳动法</button>
280→                <button class="filter-btn" data-filter="commercial">商法</button>
281→                <button class="filter-btn" data-filter="economic">经济法</button>
282→                <button class="filter-btn" data-filter="warning">高风险期限</button>
283→            </div>
284→        </header>
285→        
286→        <div class="table-container">
287→            <table id="deadlineTable">
288→                <thead>
289→                    <tr>
290→                        <th>法律门类/权利名称</th>
291→                        <th>关键期限长度</th>
292→                        <th>起算点与核心规定</th>
293→                        <th>法律后果与风险提示</th>
294→                        <th>主要法律依据</th>
295→                    </tr>
296→                </thead>
297→                <tbody>
298→                    <!-- 第一部分：劳动法、劳动合同法与社会保障法 -->
299→                    <tr class="category-row" data-category="labor">
300→                        <td colspan="5">第一部分：劳动法、劳动合同法与社会保障法</td>
301→                    </tr>
302→                    <tr class="deadline-item" data-category="labor">
303→                        <td class="sub-category">劳动争议仲裁时效</td>
304→                        <td class="time-limit">1年</td>
305→                        <td><span class="law-clause">《劳动争议调解仲裁法》第27条</span><br>自当事人知道或应当知道其权利被侵害之日起<strong>1年</strong>内提出仲裁申请。劳动关系存续期间因拖欠劳动报酬发生争议的，不受此限，但应在劳动关系终止之日起<strong>1年</strong>内提出。</td>
306→                        <td class="warning">超过仲裁时效申请仲裁，仲裁委员会可能不予受理。时效可因主张权利、同意履行等中断并重新计算。</td>
307→                        <td>《劳动争议调解仲裁法》第27条</td>
308→                    </tr>
309→                    <tr class="deadline-item" data-category="labor">
310→                        <td>未签劳动合同二倍工资差额</td>
311→                        <td class="time-limit">最多11个月<br>（时效1年）</td>
312→                        <td><span class="law-clause">《劳动合同法》第82条<br>《劳动合同法实施条例》第6、7条</span><br>用工之日起超过一个月不满一年未签，应支付二倍工资，支付时间最长不超过<strong>11个月</strong>。用工满一年未签，视为已订立无固定期限合同。<br>仲裁时效从主张权利之日倒推一年计算。</td>
313→                        <td>权利有双重期限限制：实体权利最长11个月，程序上受1年仲裁时效约束，需尽早主张。</td>
314→                        <td>《劳动合同法》第82条</td>
315→                    </tr>
316→                    <tr class="deadline-item" data-category="labor">
317→                        <td>劳动者单方解除权（预告解除）</td>
318→                        <td class="time-limit">30日/3日<br>（通知期）</td>
319→                        <td><span class="law-clause">《劳动合同法》第37条</span><br>劳动者提前<strong>30日</strong>书面通知可解除合同；试用期内提前<strong>3日</strong>通知。</td>
320→                        <td>此为法律赋予劳动者的预告期，期满后劳动关系解除。劳动者违法解除造成损失的，需赔偿。</td>
321→                        <td>《劳动合同法》第37条</td>
322→                    </tr>
323→                    <tr class="deadline-item" data-category="labor">
324→                        <td>用人单位单方解除通知工会</td>
325→                        <td class="time-limit">事先通知</td>
326→                        <td><span class="law-clause">《劳动合同法》第43条</span><br>用人单位单方解除劳动合同，应当事先将理由通知工会。工会有权提出意见。</td>
327→                        <td>未履行通知工会程序即解除，可能被认定为违法解除，需支付赔偿金（2N）。司法实践允许事后补正。</td>
328→                        <td>《劳动合同法》第43条</td>
329→                    </tr>
330→                    <tr class="deadline-item" data-category="labor">
331→                        <td>工伤认定申请</td>
332→                        <td class="time-limit">单位30日<br>个人1年</td>
333→                        <td><span class="law-clause">《工伤保险条例》第17条</span><br>单位应自事故伤害发生之日或被诊断、鉴定为职业病之日起<strong>30日</strong>内提出。<br>用人单位未提，工伤职工或其近亲属、工会可在事故伤害发生之日或被诊断、鉴定为职业病之日起<strong>1年</strong>内提出。</td>
334→                        <td class="warning">超过1年申请，人社部门可能不予受理，导致无法享受工伤待遇。</td>
335→                        <td>《工伤保险条例》第17条</td>
336→                    </tr>
337→                    
338→                    <!-- 第二部分：商法（公司法、证券法、票据法等） -->
339→                    <tr class="category-row" data-category="commercial">
340→                        <td colspan="5">第二部分：商法（公司法、证券法、票据法等）</td>
341→                    </tr>
342→                    <tr class="deadline-item" data-category="commercial">
343→                        <td class="sub-category">股东知情权诉讼</td>
344→                        <td class="time-limit">无明确期限<br>（但受诉讼时效约束）</td>
345→                        <td><span class="law-clause">《公司法》第33条、第97条</span><br>股东有权查阅、复制章程、决议、财报等。被拒绝后可请求法院要求提供查阅。法律未规定行使期限。</td>
346→                        <td>权利持续存在，但需在知道权利被侵害后的诉讼时效（3年）内起诉。</td>
347→                        <td>《公司法》第33、97条</td>
348→                    </tr>
349→                    <tr class="deadline-item" data-category="commercial warning">
350→                        <td>公司决议撤销之诉（程序瑕疵）</td>
351→                        <td class="time-limit">60日</td>
352→                        <td><span class="law-clause">《公司法》第22条</span><br>股东（会）/董事（会）召集程序、表决方式违法/违章，或内容违章，股东可自决议作出之日起<strong>60日</strong>内请求法院撤销。</td>
353→                        <td class="warning">此为除斥期间，逾期未起诉，撤销权消灭。</td>
354→                        <td>《公司法》第22条</td>
355→                    </tr>
356→                    <tr class="deadline-item" data-category="commercial">
357→                        <td>异议股东股份回购请求权</td>
358→                        <td class="time-limit">90日</td>
359→                        <td><span class="law-clause">《公司法》第74条、第142条</span><br>对股东会特定决议投反对票的股东，可请求公司以合理价格回购股份。自决议通过之日起<strong>60日</strong>内协商，<strong>90日</strong>内起诉。</td>
360→                        <td>90日内达不成协议，股东需在决议通过后90日内提起诉讼。</td>
361→                        <td>《公司法》第74、142条</td>
362→                    </tr>
363→                    <tr class="deadline-item" data-category="commercial warning">
364→                        <td>票据权利时效</td>
365→                        <td class="time-limit">2年/6个月/3个月</td>
366→                        <td><span class="law-clause">《票据法》第17条</span><br>1. 对出票人/承兑人：汇票/本票自到期日起<strong>2年</strong>，即付汇票/本票自出票日起<strong>2年</strong>。<br>2. 对支票出票人：自出票日起<strong>6个月</strong>。<br>3. 追索权：自被拒绝承兑/付款之日起<strong>6个月</strong>。<br>4. 再追索权：自清偿日/被诉之日起<strong>3个月</strong>。</td>
367→                        <td class="warning">超过票据权利时效，持票人丧失票据权利，但仍享有民事利益返还请求权（适用3年诉讼时效）。</td>
368→                        <td>《票据法》第17条</td>
369→                    </tr>
370→                    
371→                    <!-- 第三部分：经济法（反垄断、消费者权益保护等） -->
372→                    <tr class="category-row" data-category="economic">
373→                        <td colspan="5">第三部分：经济法（反垄断、消费者权益保护等）</td>
374→                    </tr>
375→                    <tr class="deadline-item" data-category="economic">
376→                        <td class="sub-category">消费者七日无理由退货</td>
377→                        <td class="time-limit">7日</td>
378→                        <td><span class="law-clause">《消费者权益保护法》第25条</span><br>经营者采用网络、电视、电话、邮购等方式销售商品，消费者自收到商品之日起<strong>7日</strong>内退货，且无需说明理由（定作、鲜活易腐等除外）。</td>
379→                        <td>经营者应自收到退回商品之日起7日内返还价款。此为法定的"冷静期"。</td>
380→                        <td>《消费者权益保护法》第25条</td>
381→                    </tr>
382→                    <tr class="deadline-item" data-category="economic">
383→                        <td>产品缺陷损害赔偿责任（诉讼时效）</td>
384→                        <td class="time-limit">2年<br>（最长10年/明示安全期）</td>
385→                        <td><span class="law-clause">《产品质量法》第45条</span><br>因产品存在缺陷造成损害要求赔偿的诉讼时效为<strong>2年</strong>，自知道或应当知道权利受损及生产者/销售者时起算。<br>损害赔偿请求权，在造成损害的缺陷产品交付最初消费者满<strong>10年</strong>丧失；未超过明示的安全使用期的除外。</td>
386→                        <td>此为特殊时效规定，短于普通3年诉讼时效。10年为最长权利保护期。</td>
387→                        <td>《产品质量法》第45条</td>
388→                    </tr>
389→                    <tr class="deadline-item" data-category="economic warning">
390→                        <td>经营者集中反垄断申报（等待期）</td>
391→                        <td class="time-limit">事前申报<br>（初审30日）</td>
392→                        <td><span class="law-clause">《反垄断法》第26条</span><br>达到申报标准的集中，应<strong>事先</strong>申报。<br>执法机构应自收到完整申报材料之日起<strong>30日</strong>内进行初步审查（第一阶段），决定是否进一步审查。</td>
393→                        <td class="warning">"抢跑"（应报未报即实施集中）面临高额罚款（最高上一年度销售额10%），可能被责令恢复原状。</td>
394→                        <td>《反垄断法》第21、26条</td>
395→                    </tr>
396→                    
397→                    <!-- 第四部分：民事实体权利除斥期间与形成权行使期限 -->
398→                    <tr class="category-row" data-category="civil">
399→                        <td colspan="5">第四部分：民事实体权利除斥期间与形成权行使期限（权利存续期，不适用中止中断）</td>
400→                    </tr>
401→                    <tr class="deadline-item" data-category="civil warning">
402→                        <td>民事法律行为撤销权</td>
403→                        <td class="time-limit">1年 / 90日<br>（最长5年）</td>
404→                        <td><span class="law-clause">《民法典》第152条</span><br>自知道或应当知道撤销事由之日起<strong>1年</strong>内行使。<br>因胁迫产生撤销权的，自胁迫行为终止之日起<strong>1年</strong>内行使。<br>重大误解当事人自知道或应当知道撤销事由之日起<strong>90日</strong>内行使。<br>自民事法律行为发生之日起<strong>5年</strong>内没有行使的，撤销权消灭。</td>
405→                        <td class="warning">逾期不行使，撤销权<strong>绝对消灭</strong>，法律行为确定有效。此为除斥期间，需主动主张。</td>
406→                        <td>《民法典》第152条</td>
407→                    </tr>
408→                    <tr class="deadline-item" data-category="civil warning">
409→                        <td>债权人撤销权</td>
410→                        <td class="time-limit">1年<br>（最长5年）</td>
411→                        <td><span class="law-clause">《民法典》第541条</span><br>自债权人知道或应当知道撤销事由之日起<strong>1年</strong>内行使。<br>自债务人的行为发生之日起<strong>5年</strong>内没有行使的，撤销权消灭。</td>
412→                        <td class="warning">逾期不行使，撤销权消灭。需通过诉讼方式行使。</td>
413→                        <td>《民法典》第538-542条</td>
414→                    </tr>
415→                    <tr class="deadline-item" data-category="civil warning">
416→                        <td>保证期间</td>
417→                        <td class="time-limit">约定优先，无约定或约定不明为6个月</td>
418→                        <td><span class="law-clause">《民法典》第692条</span><br>债权人与保证人可以约定保证期间。没有约定或约定不明确的，保证期间为主债务履行期限届满之日起<strong>6个月</strong>。<br>约定"保证人承担保证责任直至主债务本息还清时为止"等类似内容的，视为约定不明，保证期间为<strong>6个月</strong>。</td>
419→                        <td class="warning">保证期间是确定保证人是否承担责任的"生死线"。债权人在此期间内未向保证人主张权利（一般保证需起诉/仲裁），保证责任免除。</td>
420→                        <td>《民法典》第692、693条</td>
421→                    </tr>
422→                    <tr class="deadline-item" data-category="civil warning">
423→                        <td>建设工程价款优先受偿权</td>
424→                        <td class="time-limit">18个月</td>
425→                        <td><span class="law-clause">《民法典》第807条<br>《最高人民法院关于审理建设工程施工合同纠纷案件适用法律问题的解释（一）》第41条</span><br>自发包人应当给付建设工程价款之日起算。最长不超过<strong>18个月</strong>。</td>
426→                        <td class="warning">性质为法定担保物权，但行使有严格期限。逾期未主张（需通过诉讼或仲裁等方式明确请求），权利消灭。</td>
427→                        <td>《民法典》第807条<br>《建设工程施工合同司法解释一》第41条</td>
428→                    </tr>
429→                    
430→                    <!-- 第五部分：诉讼、仲裁与执行程序 -->
431→                    <tr class="category-row" data-category="procedure">
432→                        <td colspan="5">第五部分：诉讼、仲裁与执行程序</td>
433→                    </tr>
434→                    <tr class="deadline-item" data-category="procedure warning">
435→                        <td>管辖权异议期</td>
436→                        <td class="time-limit">15日</td>
437→                        <td><span class="law-clause">《民事诉讼法》第130条</span><br>被告在<strong>提交答辩状期间</strong>提出。答辩期为收到起诉状副本后15日内。</td>
438→                        <td class="warning">逾期提出，法院不予审查。此为不变期间。</td>
439→                        <td>《民事诉讼法》第130条</td>
440→                    </tr>
441→                    <tr class="deadline-item" data-category="procedure">
442→                        <td>增加、变更诉讼请求/提出反诉</td>
443→                        <td class="time-limit">举证期限届满前（原则）</td>
444→                        <td><span class="law-clause">《最高人民法院关于适用&lt;民事诉讼法&gt;的解释》第232条</span><br>原则在案件受理后，<strong>举证期限届满前</strong>提出。<br>法庭辩论结束前，对方同意或法院认为可以合并审理的，也可准许。</td>
445→                        <td>逾期提出可能导致法院不予准许，需另案处理，增加讼累。</td>
446→                        <td>《民诉法解释》第232条</td>
447→                    </tr>
448→                    <tr class="deadline-item" data-category="procedure">
449→                        <td>支付令异议期</td>
450→                        <td class="time-limit">15日</td>
451→                        <td><span class="law-clause">《民事诉讼法》第221条</span><br>债务人应当自收到支付令之日起<strong>15日</strong>内清偿债务，或向法院提出书面异议。</td>
452→                        <td>15日内不提书面异议或异议不成立，支付令生效，可申请强制执行。提出有效书面异议，支付令失效，转入诉讼程序。</td>
453→                        <td>《民事诉讼法》第221条</td>
454→                    </tr>
455→                    <tr class="deadline-item" data-category="procedure warning">
456→                        <td>仲裁裁决撤销申请</td>
457→                        <td class="time-limit">6个月</td>
458→                        <td><span class="law-clause">《仲裁法》第59条</span><br>当事人提出证据证明裁决有法定撤销情形的，可自收到裁决书之日起<strong>6个月</strong>内向仲裁委所在地中级法院申请撤销。</td>
459→                        <td class="warning">逾期未申请，撤销权消灭。</td>
460→                        <td>《仲裁法》第59条</td>
461→                    </tr>
462→                    <tr class="deadline-item" data-category="procedure">
463→                        <td>公示催告申报权利期</td>
464→                        <td class="time-limit">不少于60日</td>
465→                        <td><span class="law-clause">《民事诉讼法》第225条</span><br>法院决定受理公示催告申请后，应同时通知支付人止付，并在<strong>3日</strong>内发出公告，催促利害关系人申报权利。公示催告期间由法院定，但不得少于<strong>60日</strong>。</td>
466→                        <td>利害关系人应在公示催告期间申报权利。无人申报的，法院根据申请作出除权判决，宣告票据无效。</td>
467→                        <td>《民事诉讼法》第225条</td>
468→                    </tr>
