474→            <h3>⚠️ 重要使用说明与风险提示</h3>
475→            <ul>
476→                <li><strong>法律动态性</strong>：本表格基于现行有效法律法规（截至2026年2月）归纳整理。法律适用具有高度专业性，具体案件中期限的起算、中断、中止、延长等需严格依据最新法律、司法解释及个案事实进行精确计算。</li>
477→                <li><strong>专业管理建议</strong>：强烈建议将本表格作为建立内部"法律期限清单"的基础，并嵌入专业的案件管理软件或日历系统，设置分级预警（如提前30天、15天、7天、3天）与人工复核机制。</li>
478→                <li><strong>高风险期限</strong>：标记为<span style="color: #e74c3c; font-weight: bold;">红色警告</span>的期限为除斥期间、不变期间或过期将导致实体权利丧失的高风险期限，需特别关注。</li>
479→                <li><strong>分类筛选</strong>：使用页面顶部的分类按钮可以按法律门类筛选相关期限，使用搜索框可以快速查找特定内容。</li>
480→                <li><strong>免责声明</strong>：本汇总表仅供参考，不构成正式法律意见。具体法律事务请咨询专业律师。</li>
481→            </ul>
482→        </div>
483→        
484→        <footer>
485→            <p>© 2026 法律期限管理系统 | 数据仅供参考，请以官方最新法律法规为准</p>
486→            <p style="margin-top: 10px; font-size: 0.8em;">本页面包含劳动法、商法、经济法、民法、诉讼法等多个法律门类的关键期限规定</p>
487→        </footer>
488→    </div>
489→
490→    <script>
491→        // 搜索功能
492→        document.getElementById('searchInput').addEventListener('input', function(e) {
493→            const searchTerm = e.target.value.toLowerCase();
494→            const rows = document.querySelectorAll('.deadline-item');
495→            
496→            rows.forEach(row => {
497→                const text = row.textContent.toLowerCase();
498→                if (text.includes(searchTerm)) {
499→                    row.style.display = '';
500→                    // 添加高亮效果
501→                    row.classList.add('highlight');
502→                    setTimeout(() => {
503→                        row.classList.remove('highlight');
504→                    }, 2000);
505→                } else {
506→                    row.style.display = 'none';
507→                }
508→            });
509→            
510→            // 保持分类行显示
511→            document.querySelectorAll('.category-row').forEach(row => {
512→                row.style.display = '';
513→            });
514→        });
515→        
516→        // 筛选功能
517→        document.querySelectorAll('.filter-btn').forEach(button => {
518→            button.addEventListener('click', function() {
519→                const filter = this.getAttribute('data-filter');
520→                
521→                // 更新活动按钮
522→                document.querySelectorAll('.filter-btn').forEach(btn => {
523→                    btn.classList.remove('active');
524→                });
525→                this.classList.add('active');
526→                
527→                // 显示所有行
528→                const allRows = document.querySelectorAll('tbody tr');
529→                allRows.forEach(row => {
530→                    row.style.display = '';
531→                });
532→                
533→                // 如果选择"全部"，不进行筛选
534→                if (filter === 'all') {
535→                    return;
536→                }
537→                
538→                // 筛选行
539→                allRows.forEach(row => {
540→                    if (row.classList.contains('category-row')) {
541→                        // 分类行：检查其data-category是否包含筛选条件
542→                        const category = row.getAttribute('data-category');
543→                        if (category && category.includes(filter)) {
544→                            row.style.display = '';
545→                        } else {
546→                            // 如果不是当前筛选的分类，但下面有符合条件的项目，也显示
547→                            let hasVisibleItems = false;
548→                            let nextRow = row.nextElementSibling;
549→                            
550→                            while (nextRow && !nextRow.classList.contains('category-row')) {
551→                                if (nextRow.classList.contains('deadline-item')) {
552→                                    const itemCategories = nextRow.getAttribute('data-category');
553→                                    if (itemCategories && itemCategories.includes(filter)) {
554→                                        hasVisibleItems = true;
555→                                        break;
556→                                    }
557→                                }
558→                                nextRow = nextRow.nextElementSibling;
559→                            }
560→                            
561→                            row.style.display = hasVisibleItems ? '' : 'none';
562→                        }
563→                    } else if (row.classList.contains('deadline-item')) {
564→                        // 期限项目行：检查其data-category是否包含筛选条件
565→                        const categories = row.getAttribute('data-category');
566→                        if (categories && categories.includes(filter)) {
567→                            row.style.display = '';
568→                        } else {
569→                            row.style.display = 'none';
570→                        }
571→                    }
572→                });
573→            });
574→        });
575→        
576→        // 页面加载时显示所有内容
577→        document.addEventListener('DOMContentLoaded', function() {
578→            console.log('法律期限汇总表已加载完成，共包含 ' + document.querySelectorAll('.deadline-item').length + ' 个法律期限项目。');
579→        });
580→    </script>
581→</body>
582→</html>
