314→const CAT_NAMES = { labor:"劳动法", commercial:"商法", economic:"经济法", civil:"民事实体", procedure:"诉讼程序" };
315→const DUR_NAMES = { short:"≤15日", medium:"1-6个月", long:"1-3年", vlong:"3年以上" };
316→
317→let curCat = "all", curDur = "all", curSearch = "";
318→
319→function render() {
320→    const filtered = DATA.filter(d => {
321→        if (curCat === "warning") { if (!d.warn) return false; }
322→        else if (curCat !== "all" && d.cat !== curCat) return false;
323→        if (curDur !== "all" && d.dur !== curDur) return false;
324→        if (curSearch) {
325→            const s = curSearch.toLowerCase();
326→            const t = (d.name + d.time + d.desc + d.risk + d.law).toLowerCase();
327→            if (!t.includes(s)) return false;
328→        }
329→        return true;
330→    });
331→
332→    // 统计
333→    const total = filtered.length;
334→    const warnCount = filtered.filter(d => d.warn).length;
335→    const catCount = new Set(filtered.map(d => d.cat)).size;
336→    document.getElementById('stats').innerHTML = `
337→        <div class="stat-card"><div class="num">${total}</div><div class="label">匹配条目</div></div>
338→        <div class="stat-card warn"><div class="num">${warnCount}</div><div class="label">高风险项</div></div>
339→        <div class="stat-card"><div class="num">${catCount}</div><div class="label">涉及门类</div></div>
340→    `;
341→
342→    // 卡片
343→    const list = document.getElementById('cardList');
344→    const noRes = document.getElementById('noResult');
345→    if (!filtered.length) { list.innerHTML = ''; noRes.style.display = 'block'; return; }
346→    noRes.style.display = 'none';
347→
348→    list.innerHTML = filtered.map((d, i) => `
349→        <div class="card cat-${d.cat} ${d.warn ? 'warn-card' : ''}" onclick="this.classList.toggle('expanded')">
350→            ${d.warn ? '<div class="warn-badge">⚠ 高风险</div>' : ''}
351→            <div class="cat-tag">${CAT_NAMES[d.cat]}</div>
352→            <div class="title">${highlight(d.name)}</div>
353→            <div class="duration">${highlight(d.time)}</div>
354→            <div class="desc">${highlight(truncate(d.desc, 80))}</div>
355→            <div class="detail">
356→                <div class="desc" style="margin-bottom:10px">${highlight(d.desc)}</div>
357→                <div class="risk">${highlight(d.risk)}</div>
358→                <div class="law-ref">📖 ${highlight(d.law)}</div>
359→            </div>
360→            <div class="expand-hint">点击展开/收起详情 ▾</div>
361→        </div>
362→    `).join('');
363→}
364→
365→function truncate(s, n) { return s.length > n ? s.slice(0, n) + '...' : s; }
366→
367→function highlight(text) {
368→    if (!curSearch) return text;
369→    const re = new RegExp('(' + curSearch.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + ')', 'gi');
370→    return text.replace(re, '<mark style="background:#fbbf24;color:#0f172a;border-radius:2px;padding:0 2px">$1</mark>');
371→}
372→
373→// 事件绑定
374→document.getElementById('searchInput').addEventListener('input', e => { curSearch = e.target.value.trim(); render(); });
375→
376→document.getElementById('catFilters').addEventListener('click', e => {
377→    if (!e.target.classList.contains('fbtn')) return;
378→    document.querySelectorAll('#catFilters .fbtn').forEach(b => b.classList.remove('active'));
379→    e.target.classList.add('active');
380→    curCat = e.target.dataset.cat;
381→    render();
382→});
383→
384→document.getElementById('durFilters').addEventListener('click', e => {
385→    if (!e.target.classList.contains('dbtn')) return;
386→    document.querySelectorAll('#durFilters .dbtn').forEach(b => b.classList.remove('active'));
387→    e.target.classList.add('active');
388→    curDur = e.target.dataset.dur;
389→    render();
390→});
391→
392→window.addEventListener('scroll', () => {
393→    document.getElementById('backTop').style.display = window.scrollY > 300 ? 'block' : 'none';
394→});
395→
396→// 键盘快捷键：按 / 聚焦搜索
397→document.addEventListener('keydown', e => {
398→    if (e.key === '/' && document.activeElement !== document.getElementById('searchInput')) {
399→        e.preventDefault();
400→        document.getElementById('searchInput').focus();
401→    }
402→});
403→
404→render();
405→</script>
406→</body>
407→</html>
